mapper.select:
SELECT s.*, w.title as work_title, u.real_name as scorer_name, u2.real_name as student_name, t.name as team_name FROM scoring s LEFT JOIN work w ON s.work_id = w.id LEFT JOIN user u ON s.scorer_id = u.id LEFT JOIN user u2 ON w.student_id = u2.id LEFT JOIN team t ON w.team_id = t.id
AND s.work_id = #{workId}
AND s.scorer_id = #{scorerId}
ORDER BY s.scoring_time DESC

mapper.update:
UPDATE scoring
score = #{score}, comment = #{comment},
WHERE id = #{id}
